import React, { useEffect, useState } from 'react';
import api from '../api/axiosConfig';
import { Trash2, Download, Archive, Calendar, ShieldCheck, Zap } from 'lucide-react';
import toast from 'react-hot-toast';

const VaultPage = () => {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchHistory = async () => {
    try {
      const res = await api.get('/portfolio/history');
      setHistory(res.data);
    } catch (err) {
      toast.error("FAILED_TO_LOAD_VAULT_DATA");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Permanent Deletion: Confirm Node Wipe?")) return;
    try {
      await api.delete(`/portfolio/${id}`);
      setHistory(prev => prev.filter(item => item.id !== id));
      toast.success("STRATEGY_DELETED_FROM_VAULT");
    } catch (err) {
      toast.error("DELETION_FAILED: NODE_LOCKED");
    }
  };

  const handleDownload = async (item) => {
    try {
      // Correctly pass current item data to the export route
      const response = await api.post('/portfolio/export', item, { responseType: 'blob' });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', `Finify_Report_${item.id}.pdf`);
      document.body.appendChild(link);
      link.click();
      link.remove();
    } catch (err) {
      toast.error("PDF_SYNTHESIS_FAILED");
    }
  };

  useEffect(() => { fetchHistory(); }, []);

  if (loading) return <div style={centerStyle}>SYNCHRONIZING_VAULT...</div>;

  return (
    <div className="reveal-node" style={containerStyle}>
      <h2 style={headerStyle}><Archive size={20} color="var(--accent-primary)"/> STRATEGY_VAULT</h2>
      
      {history.length === 0 ? (
        <div style={emptyStyle}>No records found. Initialize a new strategy to populate the vault.</div>
      ) : (
        <div style={listStyle}>
          {history.map((item) => (
            <div key={item.id} style={cardStyle}>
              <div style={{ flex: 1 }}>
                <div style={tagRow}>
                  <span style={dateTag}><Calendar size={10}/> {new Date(item.created_at).toLocaleDateString()}</span>
                  <span style={riskTag}><ShieldCheck size={10}/> RISK_LVL: {item.risk_score}</span>
                </div>
                <h4 style={titleStyle}>{item.goal}</h4>
                <p style={summaryStyle}>{item.summary}</p>
                <div style={tickerRow}>
                   {JSON.parse(item.holdings || "[]").map((t, i) => (
                     <span key={i} style={tickerTag}>{t}</span>
                   ))}
                </div>
              </div>
              <div style={actionRow}>
                <button onClick={() => handleDownload(item)} style={iconBtn} title="Download Report"><Download size={18}/></button>
                <button onClick={() => handleDelete(item.id)} style={deleteBtn} title="Delete Record"><Trash2 size={18}/></button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

/* --- Terminal Styles --- */
const containerStyle = { padding: '2rem 1rem', maxWidth: '900px', margin: '0 auto' };
const headerStyle = { color: 'var(--text-primary)', display: 'flex', alignItems: 'center', gap: '12px', fontSize: '1.2rem', letterSpacing: '0.1em', marginBottom: '2rem' };
const listStyle = { display: 'flex', flexDirection: 'column', gap: '1rem' };
const cardStyle = { display: 'flex', padding: '1.5rem', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)', borderRadius: '16px', gap: '1.5rem', transition: 'all 0.3s ease' };
const tagRow = { display: 'flex', gap: '1rem', marginBottom: '0.75rem' };
const dateTag = { fontSize: '0.6rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '4px', textTransform: 'uppercase' };
const riskTag = { fontSize: '0.6rem', color: 'var(--accent-primary)', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '4px' };
const titleStyle = { margin: '0 0 0.5rem', color: 'var(--text-primary)', fontSize: '1rem', fontWeight: 700 };
const summaryStyle = { margin: '0 0 1rem', fontSize: '0.8rem', color: 'var(--text-secondary)', lineHeight: 1.5 };
const tickerRow = { display: 'flex', flexWrap: 'wrap', gap: '6px' };
const tickerTag = { fontSize: '0.65rem', padding: '2px 6px', background: 'rgba(16,185,129,0.1)', border: '1px solid var(--accent-primary)', borderRadius: '4px', color: 'var(--accent-primary)', fontFamily: 'monospace' };
const actionRow = { display: 'flex', flexDirection: 'column', gap: '0.5rem', borderLeft: '1px solid var(--surface-border)', paddingLeft: '1.5rem' };
const iconBtn = { background: 'none', border: 'none', color: 'var(--text-secondary)', cursor: 'pointer', padding: '8px', borderRadius: '8px', transition: 'all 0.2s' };
const deleteBtn = { ...iconBtn, color: '#ef4444' };
const centerStyle = { height: '50vh', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent-primary)', fontFamily: 'monospace', letterSpacing: '0.2em' };
const emptyStyle = { textAlign: 'center', color: 'var(--text-muted)', padding: '4rem', background: 'var(--surface-glass)', borderRadius: '16px', border: '1px dashed var(--surface-border)' };

export default VaultPage;
